const input = $input.first().json;
const updates = input.result || [];
if (updates.length === 0) return [];
const maxId = Math.max(...updates.map(u => u.update_id));
return updates.filter(u => u.message).map(u => ({ json: { message: u.message, new_offset: String(maxId + 1) } }));

const msg = $('Process Updates').item.json.message;
const text = (msg.text || '').trim();
const chat_id = msg.chat.id;
const has_voice = !!msg.voice;

if (has_voice || !text.startsWith('/')) {
  return [{ json: { is_command: false, message: msg } }];
}

const parts = text.split(/\s+/);
const cmd = parts[0].toLowerCase().replace(/@.*/, '');
const args = parts.slice(1).join(' ');

// Optional multi-project support: read PROJECTS env var (CSV)
const PROJECTS = ($env.PROJECTS || '').split(',').map(s => s.trim()).filter(Boolean);
const MULTI_PROJECT = PROJECTS.length > 0;
function parseProject(tok) {
  if (!tok || !MULTI_PROJECT) return null;
  const lc = String(tok).toLowerCase();
  return PROJECTS.find(p => p.toLowerCase() === lc) || null;
}
function extractProjectAndRest(argString) {
  const toks = argString.trim().split(/\s+/).filter(Boolean);
  let project = null;
  const rest = [];
  for (const t of toks) {
    const p = parseProject(t);
    if (p && !project) project = p;
    else rest.push(t);
  }
  return { project, rest: rest.join(' ') };
}

let response = '';
let action = null;

if (cmd === '/start' || cmd === '/help') {
  const projectLine = MULTI_PROJECT
    ? '\n<b>Projects:</b> ' + PROJECTS.join(', ') + '\nPrefix or mention a project name in your message to route it, or add it as a filter on browse commands: /list ' + PROJECTS[0] + '\n'
    : '';
  response = '\ud83e\udde0 <b>Batty - Ideas Bot</b>\n\nSend voice or text to capture ideas.' + projectLine + '\n<b>Browse</b>\n/list - Show active ideas (latest 10)\n/list all - All active ideas\n/status - Dashboard\n/archive - Archived ideas\n\n<b>Manage</b>\n/edit 3 title New title\n/edit 3 desc New description\n/priority 3 P1\n/done 3\n/reject 3\n/delete 3\n\n/help - This message';
} else if (cmd === '/list') {
  const { project, rest } = extractProjectAndRest(args);
  if (rest.toLowerCase() === 'all') {
    action = { type: 'list', all: true, project };
  } else {
    action = { type: 'list', page: parseInt(rest) || 1, project };
  }
} else if (cmd === '/status') {
  const { project } = extractProjectAndRest(args);
  action = { type: 'status', project };
} else if (cmd === '/edit' && args) {
  const m = args.match(/^(\d+)\s+(title|desc|description)\s+(.+)/is);
  if (m) {
    const field = m[2].toLowerCase().startsWith('desc') ? 'description' : 'title';
    action = { type: 'patch', id: parseInt(m[1]), data: { [field]: m[3].trim() } };
  } else response = '\u274c Usage: /edit &lt;id&gt; title|desc &lt;new text&gt;';
} else if (cmd === '/delete' && args) {
  const id = parseInt(args);
  if (id) action = { type: 'delete', id };
  else response = '\u274c Usage: /delete <id>';
} else if (cmd === '/done' && args) {
  const id = parseInt(args);
  if (id) action = { type: 'patch', id, data: { status: 'done' } };
  else response = '\u274c Usage: /done <id>';
} else if (cmd === '/reject' && args) {
  const id = parseInt(args);
  if (id) action = { type: 'patch', id, data: { status: 'rejected' } };
  else response = '\u274c Usage: /reject <id>';
} else if (cmd === '/priority' && args) {
  const m = args.match(/(\d+)\s+(P[0-3])/i);
  if (m) {
    const pMap = { P0: '-critical', P1: '-high', P2: '-medium', P3: '-low' };
    action = { type: 'patch', id: parseInt(m[1]), data: { priority: m[2].toUpperCase() + (pMap[m[2].toUpperCase()] || '') } };
  } else response = '\u274c Usage: /priority &lt;id&gt; &lt;P0|P1|P2|P3&gt;';
} else if (cmd === '/archive') {
  const { project, rest } = extractProjectAndRest(args);
  if (rest.toLowerCase() === 'all') {
    action = { type: 'archive', all: true, project };
  } else {
    action = { type: 'archive', page: parseInt(rest) || 1, project };
  }
} else {
  response = '\u2753 Unknown command. Try /help';
}

return [{ json: { is_command: true, chat_id, response, action } }];

const input = $json;
const action = input.action;
const chat_id = input.chat_id;

if (input.response) {
  return [{ json: { chat_id, text: input.response, needs_api: false } }];
}
if (!action) return [];

const baseUrl = 'http://ideas-store:9321';
let url = '', method = 'GET', body = '';
const action_type = action.type;
const action_data_json = JSON.stringify(action.data || {});

function addProject(u, project) {
  if (!project) return u;
  return u + (u.includes('?') ? '&' : '?') + 'project=' + encodeURIComponent(project);
}

if (action.type === 'list') {
  url = baseUrl + '/ideas/list' + (action.all ? '?all=true' : '?page=' + action.page);
  url = addProject(url, action.project);
} else if (action.type === 'status') {
  url = baseUrl + '/ideas/status';
  url = addProject(url, action.project);
} else if (action.type === 'archive') {
  url = baseUrl + '/ideas/archive' + (action.all ? '?all=true' : '?page=' + action.page);
  url = addProject(url, action.project);
} else if (action.type === 'delete') {
  url = baseUrl + '/ideas/' + action.id;
  method = 'DELETE';
} else if (action.type === 'patch') {
  url = baseUrl + '/ideas/' + action.id;
  method = 'PATCH';
  body = JSON.stringify(action.data);
}

return [{ json: { chat_id, url, method, body, action_type, action_data_json, needs_api: true } }];

const apiRes = $json;
const req = $('Build Request').item.json;
const chat_id = req.chat_id;
const action_type = req.action_type;
const action_data = JSON.parse(req.action_data_json || '{}');

if (action_type === 'list' || action_type === 'status' || action_type === 'archive') {
  return [{ json: { chat_id, text: apiRes.text || 'No data' } }];
}
if (action_type === 'delete') {
  if (apiRes.ok) return [{ json: { chat_id, text: '\ud83d\uddd1 Deleted: ' + apiRes.deleted } }];
  return [{ json: { chat_id, text: '\u274c ' + (apiRes.error || 'Delete failed') } }];
}
if (action_type === 'patch') {
  if (apiRes.ok) {
    const idea = apiRes.updated;
    if (action_data.title || action_data.description) {
      const field = action_data.title ? 'title' : 'description';
      let txt = '\u270f\ufe0f <b>#' + idea.id + '</b> ' + field + ' updated\n';
      txt += '<b>' + idea.title + '</b>';
      if (action_data.description) txt += '\n<i>' + idea.description + '</i>';
      return [{ json: { chat_id, text: txt } }];
    }
    let emoji = action_data.status === 'done' ? '\u2705' : action_data.status === 'rejected' ? '\u274c' : '\u2699\ufe0f';
    let txt = emoji + ' <b>#' + idea.id + '</b> ' + idea.title;
    if (action_data.priority) txt += ' \u2192 ' + idea.priority;
    if (action_data.status) txt += ' \u2192 ' + idea.status;
    return [{ json: { chat_id, text: txt } }];
  }
  return [{ json: { chat_id, text: '\u274c ' + (apiRes.error || 'Update failed') } }];
}
return [{ json: { chat_id, text: '\u2753 Unknown action' } }];

const input = $input.first().json;

const PROJECTS = ($env.PROJECTS || '').split(',').map(s => s.trim()).filter(Boolean);
const MULTI_PROJECT = PROJECTS.length > 0;
const DEFAULT_PROJECT = PROJECTS[0] || null;
function normalizeProject(v) {
  if (!MULTI_PROJECT) return undefined;
  if (!v) return DEFAULT_PROJECT;
  const lc = String(v).toLowerCase();
  return PROJECTS.find(p => p.toLowerCase() === lc) || DEFAULT_PROJECT;
}

let ideas;
try {
  let text = input.choices[0].message.content.trim();
  if (text.startsWith('\u0060\u0060\u0060')) text = text.replace(/^\u0060\u0060\u0060(?:json)?\n?/, '').replace(/\n?\u0060\u0060\u0060$/, '');
  ideas = JSON.parse(text);
} catch (e) {
  try {
    const match = input.choices[0].message.content.match(/\[.*\]/s);
    if (match) ideas = JSON.parse(match[0]);
    else throw new Error('no json');
  } catch(e2) {
    ideas = [{ title: 'Raw capture (auto-parse failed)', description: 'Could not structure automatically.', category: 'feature', priority: 'P2-medium', raw_input: 'parse_error' }];
  }
}

// Resolve chat_id FIRST (before any early returns)
let source_type = 'text', language = 'auto', chat_id = 0;
try { source_type = $('Set Text Input').first().json.source_type; language = $('Set Text Input').first().json.language; chat_id = $('Set Text Input').first().json.chat_id; } catch(e) {}
try { if (!chat_id) { source_type = $('Set Voice Text').first().json.source_type; language = $('Set Voice Text').first().json.language; chat_id = $('Set Voice Text').first().json.chat_id; } } catch(e) {}

const noIdea = ideas.find(i => i.category === 'none');
ideas = ideas.filter(i => i.category !== 'none');
if (ideas.length === 0) return [{ json: { skip: true, chat_id, reason: noIdea ? noIdea.description : 'No actionable idea detected.' } }];

const now = new Date().toISOString();
return [{ json: { ideas: ideas.map(idea => {
  const out = { ...idea, source_type, language, timestamp: now, status: 'new', chat_id };
  if (MULTI_PROJECT) out.project = normalizeProject(idea.project);
  return out;
}), chat_id } }];

